+ *
+ * ****************************************************************/
+
+
+uint8_t buildandsendfapimsgtofapidecoder(p_fapi_api_queue_elem_t msg) 
+{
+    // Create and connect socket
+    if(sockfd==0)
+    {
+       sockfd = create_socket("127.0.0.1", 8080);
+       if(sockfd<=0)
