diff --git a/openair3/NGAP/ngap_gNB_NRPPa_transport_procedures.c b/openair3/NGAP/ngap_gNB_NRPPa_transport_procedures.c
--- a/openair3/NGAP/ngap_gNB_NRPPa_transport_procedures.c
+++ b/openair3/NGAP/ngap_gNB_NRPPa_transport_procedures.c
@@ -0,0 +1,129 @@
