+            pcrf_event_t *e = NULL;
+
+            rv = ogs_queue_trypop(ogs_app()->queue, (void**)&e);
+            ogs_assert(rv != OGS_ERROR);
+
+            if (rv == OGS_DONE)
+                goto done;
+
+            if (rv == OGS_RETRY)
+                break;
+
+            ogs_assert(e);
+            ogs_fsm_dispatch(&pcrf_sm, e);
+            pcrf_event_free(e);
+        }
     }
+done:
+
+    ogs_fsm_fini(&pcrf_sm, 0);
 }

